const health = $('2. GET /api/health').item.json;
const metricas = $('3. GET /api/metricas').item.json;

const alertas = [];

// 1. Status geral
if (!health.checks?.supabase?.ok) {
  alertas.push({ nivel: 'CRITICO', tipo: 'supabase_offline', mensagem: 'Supabase está offline. Nenhuma ingestão possível.' });
}

if (!health.checks?.ai_chat?.ok) {
  alertas.push({ nivel: 'CRITICO', tipo: 'ai_chat_offline', mensagem: `Provedor de IA (${health.checks?.ai_chat?.provider}) está inacessível. Respostas assistidas paradas.` });
}

if (health.checks?.embedding?.ok === false) {
  alertas.push({ nivel: 'AVISO', tipo: 'embedding_offline', mensagem: `Embeddings indisponíveis (${health.checks?.embedding?.provider}). Busca vetorial desativada, usando fallback textual.` });
}

if (health.checks?.pgvector_rpc?.ok === false) {
  alertas.push({ nivel: 'AVISO', tipo: 'pgvector_rpc_ausente', mensagem: 'Função buscar_atendimentos_semanticos não encontrada. Execute a migration 002_upgrade_semantic_search.sql.' });
}

// 2. Cobertura de embeddings
const coverage = health.checks?.embedding_coverage?.pct;
if (coverage !== null && coverage !== undefined && coverage < 0.7) {
  alertas.push({ nivel: 'AVISO', tipo: 'embedding_coverage_baixo', mensagem: `Apenas ${Math.round(coverage * 100)}% dos atendimentos processados têm embedding. Execute scripts/backfill-embeddings.ts.` });
}

// 3. Backlog de processamento
const backlog = metricas.saude?.pendentes_acumulados ?? 0;
if (backlog > 20) {
  alertas.push({ nivel: 'AVISO', tipo: 'backlog_processamento', mensagem: `${backlog} atendimentos aguardam processamento há mais de 5 minutos. Verifique a fila.` });
}

// 4. Erros de auditoria
const auditErrors = metricas.saude?.audit_errors_24h ?? 0;
if (auditErrors > 10) {
  alertas.push({ nivel: 'AVISO', tipo: 'muitos_erros_auditoria', mensagem: `${auditErrors} erros registrados nas últimas 24h em audit_events.` });
}

// 5. Latência alta
const supabaseLatency = health.checks?.supabase?.latency_ms ?? 0;
if (supabaseLatency > 2000) {
  alertas.push({ nivel: 'AVISO', tipo: 'latencia_supabase_alta', mensagem: `Latência do Supabase: ${supabaseLatency}ms (limite: 2000ms).` });
}

const saudavel = alertas.length === 0;
const temCritico = alertas.some(a => a.nivel === 'CRITICO');

return [{
  json: {
    saudavel,
    tem_critico: temCritico,
    total_alertas: alertas.length,
    alertas,
    status: health.status ?? 'inacessivel',
    embedding_coverage_pct: coverage !== null && coverage !== undefined ? Math.round(coverage * 100) : null,
    backlog: backlog,
    audit_errors_24h: auditErrors,
    timestamp: new Date().toISOString()
  }
}];

// Formatar mensagem de alerta legível
const d = $json;
const linhas = [
  `🚨 ALERTA CÉREBRO — ${d.timestamp}`,
  `Status: ${d.status.toUpperCase()}`,
  `Alertas: ${d.total_alertas} | Críticos: ${d.tem_critico ? 'SIM' : 'Não'}`,
  '',
  ...d.alertas.map(a => `${a.nivel === 'CRITICO' ? '🔴' : '🟡'} [${a.nivel}] ${a.mensagem}`),
  '',
  `Embedding coverage: ${d.embedding_coverage_pct !== null ? d.embedding_coverage_pct + '%' : 'N/A'}`,
  `Backlog: ${d.backlog} tickets`,
  `Erros 24h: ${d.audit_errors_24h}`,
];

return [{ json: { ...d, mensagem_formatada: linhas.join('\n') } }];
